import base64
import json
import os
import sys
import time
from typing import Any, Dict

import pika


def die(msg: str, code: int = 2) -> None:
    print(f"[ERROR] {msg}", file=sys.stderr)
    sys.exit(code)


def load_package(path: str) -> Dict[str, Any]:
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except FileNotFoundError:
        die(f"Package JSON not found: {path}")
    except json.JSONDecodeError as e:
        die(f"Invalid JSON in {path}: {e}")


def get(d: Dict[str, Any], path: str, default: Any = None) -> Any:
    cur: Any = d
    for part in path.split("."):
        if not isinstance(cur, dict) or part not in cur:
            return default
        cur = cur[part]
    return cur


def decode_body(body: bytes, how: str) -> str:
    if how == "base64":
        return base64.b64encode(body).decode("ascii")
    return body.decode("utf-8", errors="replace")


def maybe_declare_queue(ch: pika.channel.Channel, cfg: Dict[str, Any]) -> None:
    if not bool(get(cfg, "queue.declare", False)):
        return

    q = get(cfg, "queue", {}) or {}
    name = q.get("name")
    if not name:
        die("configuration.queue.name is required")

    ch.queue_declare(
        queue=name,
        durable=bool(q.get("durable", True)),
        exclusive=bool(q.get("exclusive", False)),
        auto_delete=bool(q.get("autoDelete", False)),
        arguments=q.get("arguments") or None,
    )


def main() -> None:
    config_path = os.environ.get("CONNECTOR_JSON_PATH", "/run/connector.json")

    pkg = load_package(config_path)

    amqp_url = get(pkg, "auth.amqpUrl")
    if not amqp_url or not isinstance(amqp_url, str):
        die("Missing required auth.amqpUrl")

    cfg = get(pkg, "configuration", {}) or {}

    mode = cfg.get("mode", "queue")
    if mode != "queue":
        die("Only configuration.mode='queue' is supported")

    queue_name = get(cfg, "queue.name")
    if not queue_name:
        die("configuration.queue.name is required")

    consume_timeout_ms = int(get(cfg, "consume.timeoutMs", 30000))
    message_limit = int(get(cfg, "consume.messageLimit", 1))
    auto_ack = bool(get(cfg, "consume.autoAck", False))
    prefetch = int(get(cfg, "consume.prefetchCount", 10))
    exit_on_empty = bool(get(cfg, "consume.exitOnEmptyQueue", False))

    out_format = str(get(cfg, "output.format", "json"))
    out_decode = str(get(cfg, "output.decode", "utf-8"))
    include_props = bool(get(cfg, "output.includeProperties", True))

    if consume_timeout_ms <= 0:
        die("configuration.consume.timeoutMs must be > 0")
    if message_limit <= 0:
        die("configuration.consume.messageLimit must be > 0")

    params = pika.URLParameters(amqp_url)

    try:
        conn = pika.BlockingConnection(params)
    except Exception as e:
        die(f"Failed to connect: {e}")

    ch = conn.channel()
    ch.basic_qos(prefetch_count=prefetch)

    maybe_declare_queue(ch, cfg)

    start = time.time()
    timeout_s = consume_timeout_ms / 1000.0
    consumed = 0

    print(f"[INFO] Connected. queue='{queue_name}' messageLimit={message_limit} timeoutMs={consume_timeout_ms} autoAck={auto_ack}")

    try:
        while consumed < message_limit and (time.time() - start) < timeout_s:
            method, props, body = ch.basic_get(queue=queue_name, auto_ack=auto_ack)

            if method is None:
                if exit_on_empty:
                    print("[INFO] Queue empty; exiting (exitOnEmptyQueue=true)")
                    break
                time.sleep(0.25)
                continue

            consumed += 1

            decoded = decode_body(body, out_decode)

            if out_format == "raw":
                print(decoded)
            else:
                obj: Dict[str, Any] = {
                    "deliveryTag": method.delivery_tag,
                    "exchange": method.exchange,
                    "routingKey": method.routing_key,
                    "redelivered": method.redelivered,
                    "body": decoded,
                }
                if include_props and props is not None:
                    obj["properties"] = {
                        "content_type": props.content_type,
                        "content_encoding": props.content_encoding,
                        "headers": props.headers,
                        "delivery_mode": props.delivery_mode,
                        "priority": props.priority,
                        "correlation_id": props.correlation_id,
                        "reply_to": props.reply_to,
                        "expiration": props.expiration,
                        "message_id": props.message_id,
                        "timestamp": props.timestamp,
                        "type": props.type,
                        "user_id": props.user_id,
                        "app_id": props.app_id,
                    }
                print(json.dumps(obj, ensure_ascii=False))

            if not auto_ack:
                ch.basic_ack(delivery_tag=method.delivery_tag)

        if consumed >= message_limit:
            print(f"[INFO] Reached messageLimit={message_limit}. Exiting.")
        else:
            print(f"[INFO] Timeout reached after {consume_timeout_ms} ms. Consumed={consumed}. Exiting.")

    except KeyboardInterrupt:
        print("[INFO] Interrupted by user. Exiting.")
    finally:
        try:
            conn.close()
        except Exception:
            pass


if __name__ == "__main__":
    main()
